# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorRef, ActorSystem, Props}

// Message protocol
sealed trait BankMessage
case class Deposit(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case class Withdraw(amount: BigDecimal, replyTo: Option[ActorRef] = None) extends BankMessage
case object GetBalance extends BankMessage
case class BalanceResponse(balance: BigDecimal)
case class TransactionResult(success: Boolean, message: String, currentBalance: BigDecimal)

// Account Actor - Akka actors process messages one at a time from their mailbox,
// so the var is safely accessed sequentially by the actor's single thread.
// No external synchronization is needed because the actor model guarantees
// that only one message is processed at a time within a single actor instance.
// IMPORTANT: Never expose `balance` directly or share mutable state outside the actor.
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // This var is safe because Akka guarantees single-threaded message processing
  // per actor instance. No two messages will ever be processed concurrently
  // within this actor.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount, replyTo) =>
      if (amount <= 0) {
        val result = TransactionResult(
          success = false,
          message = s"Invalid deposit amount: $amount. Must be positive.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else {
        balance += amount
        val result = TransactionResult(
          success = true,
          message = s"Deposited $amount to account $accountId.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      }

    case Withdraw(amount, replyTo) =>
      if (amount <= 0) {
        val result = TransactionResult(
          success = false,
          message = s"Invalid withdrawal amount: $amount. Must be positive.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else if (amount > balance) {
        val result = TransactionResult(
          success = false,
          message = s"Insufficient funds in account $accountId. Requested: $amount, Available: $balance.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      } else {
        balance -= amount
        val result = TransactionResult(
          success = true,
          message = s"Withdrew $amount from account $accountId.",
          currentBalance = balance
        )
        replyTo.getOrElse(sender()).tell(result, self)
      }

    case GetBalance =>
      sender() ! BalanceResponse(balance)
  }
}

object AccountActor {
  def props(accountId: String, initialBalance: BigDecimal = BigDecimal(0)): Props =
    Props(new AccountActor(accountId, initialBalance))
}

// Account Manager - routes messages to the correct account actor
class AccountManagerActor extends Actor {
  import scala.collection.mutable

  private val accounts: mutable.Map[String, ActorRef] = mutable.Map.empty

  override def receive: Receive = {
    case (accountId: String, msg: BankMessage) =>
      val accountRef = accounts.getOrElseUpdate(accountId, {
        context.actorOf(AccountActor.props(accountId), s"account-$accountId")
      })
      accountRef.forward(msg)

    case CreateAccount(accountId, initialBalance) =>
      if (accounts.contains(accountId)) {
        sender() ! TransactionResult(false, s"Account $accountId already exists.", BigDecimal(0))
      } else {
        val ref = context.actorOf(AccountActor.props(accountId, initialBalance), s"account-$accountId")
        accounts(accountId) = ref
        sender() ! TransactionResult(true, s"Account $accountId created with balance $initialBalance.", initialBalance)
      }
  }
}

case class CreateAccount(accountId: String, initialBalance: BigDecimal = BigDecimal(0))

object AccountManagerActor {
  def props(): Props = Props(new AccountManagerActor)
}

// Demo application
object BankingApp extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("BankingSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  import system.dispatcher

  val manager = system.actorOf(AccountManagerActor.props(), "account-manager")

  // Create accounts
  val setup = for {
    r1 <- (manager ? CreateAccount("ACC-001", BigDecimal(1000))).mapTo[TransactionResult]
    r2 <- (manager ? CreateAccount("ACC-002", BigDecimal(500))).mapTo[TransactionResult]
  } yield {
    println(r1)
    println(r2)
  }

  Await.result(setup, 5.seconds)

  // Simulate concurrent transactions
  val transactions: Seq[Future[TransactionResult]] = Seq(
    (manager ? ("ACC-001", Deposit(BigDecimal(200)))).mapTo[TransactionResult],
    (manager ? ("ACC-001", Withdraw(BigDecimal(150)))).mapTo[TransactionResult],
    (manager ? ("ACC-001", Deposit(BigDecimal(300)))).mapTo[TransactionResult],
    (manager ? ("ACC-002", Deposit(BigDecimal(100)))).mapTo[TransactionResult],
    (manager ? ("ACC-002", Withdraw(BigDecimal(50)))).mapTo[TransactionResult],
    (manager ? ("ACC-001", Withdraw(BigDecimal(5000)))).mapTo[TransactionResult] // Should fail
  )

  val allResults = Future.sequence(transactions)
  val results = Await.result(allResults, 10.seconds)
  results.foreach(println)

  // Check final balances
  val balances = for {
    b1 <- (manager ? ("ACC-001", GetBalance)).mapTo[BalanceResponse]
    b2 <- (manager ? ("ACC-002", GetBalance)).mapTo[BalanceResponse]
  } yield {
    println(s"ACC-001 final balance: ${b1.balance}")
    println(s"ACC-002 final balance: ${b2.balance}")
  }

  Await.result(balances, 5.seconds)

  system.terminate()
}